import{_ as s,o as a,c as t,ah as i}from"./chunks/framework.C8Zd3T50.js";const k=JSON.parse('{"title":"Local storage paths","description":"","frontmatter":{},"headers":[],"relativePath":"local-storage.md","filePath":"local-storage.md"}'),o={name:"local-storage.md"};function n(r,e,l,d,h,c){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="local-storage-paths" tabindex="-1">Local storage paths <a class="header-anchor" href="#local-storage-paths" aria-label="Permalink to &quot;Local storage paths&quot;">​</a></h1><p>Some os384 services write local state that is deliberately kept <strong>outside</strong> the project tree — and outside the user&#39;s home directory entirely. The reasons are:</p><ul><li><strong>Backup hygiene.</strong> Shard caches and wrangler KV state are large, ephemeral, or fully regenerable. They should not be swept up by tools like <code>restic</code> that back up everything under <code>~/</code>.</li><li><strong>Clear separation.</strong> Dev/test infrastructure state is distinct from source code and personal data.</li></ul><h2 id="macos-—-recommended-setup" tabindex="-1">macOS — recommended setup <a class="header-anchor" href="#macos-—-recommended-setup" aria-label="Permalink to &quot;macOS — recommended setup&quot;">​</a></h2><p>Create a dedicated APFS volume inside your existing disk container. APFS volumes share free space dynamically — no fixed allocation needed.</p><p>First, identify your APFS container disk:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">diskutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p>Look for a <code>(synthesized)</code> entry of type <code>APFS Container Scheme</code> that contains your main <code>Macintosh HD</code> / <code>Data</code> volumes. On most modern Macs this is <code>disk3</code>, but verify — it could differ on your machine (e.g. if you have external drives connected at boot, or a non-standard partition layout).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dev/disk3 (synthesized):          ← this is the one you want</span></span>
<span class="line"><span>   #:  TYPE                  NAME</span></span>
<span class="line"><span>   0:  APFS Container Scheme  -      2.0 TB   disk3</span></span>
<span class="line"><span>   1:  APFS Volume            Macintosh HD</span></span>
<span class="line"><span>   ...</span></span></code></pre></div><p>Then add the new volume to that container:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">diskutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addVolume</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> disk3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> APFS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> os384</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># mounts automatically at /Volumes/os384 on every boot</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chown</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whoami</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/Volumes/os384</span></span></code></pre></div><p>That&#39;s the only manual step. Subdirectories are created automatically the first time you run any service via the Makefile (see below).</p><h2 id="linux-—-recommended-paths" tabindex="-1">Linux — recommended paths <a class="header-anchor" href="#linux-—-recommended-paths" aria-label="Permalink to &quot;Linux — recommended paths&quot;">​</a></h2><p><code>/opt/os384/</code> follows FHS convention for add-on software state. <code>/var/cache/os384/</code> is the correct FHS location for regenerable cache data. As with macOS, subdirectory creation is handled automatically by the Makefile.</p><h2 id="environment-variables" tabindex="-1">Environment variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment variables&quot;">​</a></h2><p>These variables control where wrangler and mirror store their local state. Both have sensible defaults for macOS — you only need to set them if you want a different location or are on Linux.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default (macOS)</th><th>Linux recommended</th><th>Purpose</th></tr></thead><tbody><tr><td><code>OS384_WRANGLER_STATE</code></td><td><code>/Volumes/os384/wrangler</code></td><td><code>/opt/os384</code></td><td>Root directory for wrangler local KV / DO state</td></tr><tr><td><code>OS384_MIRROR_CACHE_DIR</code></td><td><code>/Volumes/os384/mirror/shards</code></td><td><code>/var/cache/os384/mirror/shards</code></td><td>Shard cache directory for the mirror server</td></tr></tbody></table><p>To override, set them in your shell profile (<code>~/.zshrc</code>, <code>~/.bashrc</code>, etc.) or in a sourced env file (see <code>env.example.sh</code> in the repo root):</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># os384 local storage — override defaults if needed</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OS384_WRANGLER_STATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/Volumes/os384/wrangler  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS default</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OS384_MIRROR_CACHE_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/Volumes/os384/mirror/shards   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS default</span></span></code></pre></div><p>If <code>OS384_WRANGLER_STATE</code> is not set, the <code>services/Makefile</code> defaults to <code>/Volumes/os384/wrangler</code> and creates the directory automatically. If the directory cannot be created, the Makefile will print an error and exit with a link back to this page.</p><h2 id="makefile-integration" tabindex="-1">Makefile integration <a class="header-anchor" href="#makefile-integration" aria-label="Permalink to &quot;Makefile integration&quot;">​</a></h2><p>The <code>services/Makefile</code> has an <code>ensure-local-storage</code> target that creates both directories idempotently. All service start targets (<code>dev-storage</code>, <code>dev-channel</code>) depend on it, so setup is automatic on first run:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev-storage</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # creates dirs if needed, then starts storage worker</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev-channel</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # same, then starts channel worker</span></span></code></pre></div><p>You can also run it standalone as a quick check:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ensure-local-storage</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Local storage OK</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   wrangler state : /Volumes/os384/wrangler</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   mirror cache   : /Volumes/os384/mirror/shards</span></span></code></pre></div><p>If either directory cannot be created you&#39;ll get a clear error pointing back to this page rather than a silent failure.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><p>The wrangler <code>--persist-to</code> flag <strong>cannot</strong> be set inside <code>wrangler.toml</code> — it is CLI-only and must be passed on every <code>wrangler dev</code> invocation. The <code>services/Makefile</code> handles this for both <code>dev-storage</code> and <code>dev-channel</code>, pointing both at the same state directory so they share KV namespaces.</p></li><li><p>Both <code>storage</code> and <code>channel</code> workers share the same wrangler state directory. This is intentional: the channel worker needs to read LEDGER_NAMESPACE which storage writes to. Passing the same <code>--persist-to</code> path to both achieves this without any symlink setup.</p></li><li><p>Mirror&#39;s <code>OS384_MIRROR_CACHE_DIR</code> points directly to the shards directory (not its parent). The directory is created automatically by <code>mirror.py</code> on startup if it does not exist.</p></li><li><p>Linux support for this layout is tracked in <code>services/TODO.md</code>. Docker volume placement is also tracked there.</p></li></ul>`,28)])])}const u=s(o,[["render",n]]);export{k as __pageData,u as default};
